const app = initializeApp(firebaseConfig);
const db  = getFirestore(app);

async function fsGet(col, id) {
  try { const s = await getDoc(doc(db,col,id)); return s.exists()?{_id:s.id,...s.data()}:null; } catch(e){ return null; }
}
async function fsSet(col, id, data) {
  try { await setDoc(doc(db,col,id), data); return true; } catch(e){ return false; }
}
async function fsDel(col, id) {
  try { await deleteDoc(doc(db,col,id)); return true; } catch(e){ return false; }
}
async function fsAll(col) {
  try { const s=await getDocs(collection(db,col)); return s.docs.map(d=>({_id:d.id,...d.data()})); } catch(e){ return []; }
}

