window.doLogin = async function(){
  const u=document.getElementById('lu').value.trim(), p=document.getElementById('lp').value.trim();
  const lerr=document.getElementById('lerr'); lerr.textContent='Giriş yapılıyor...';
  const all=await fsAll('pers');
  const found=all.find(x=>x.username===u&&x.password===p);
  if(!found){lerr.textContent='❌ Hatalı kullanıcı adı veya şifre.';return;}
  if(found.isAdmin===undefined) found.isAdmin=(found.username==='admin');
  CU=found; lerr.textContent='';
  await logAct('Sisteme giriş yapıldı.');
  showDash();
};

window.doLogout = function(){
  if(mesaiStart) endMesai();
  stopTimerDisplay();
  logAct('Sistemden çıkış yapıldı.');
  CU=null; showPScreen('login');
  const lu=document.getElementById('lu'); if(lu) lu.value='';
  const lp=document.getElementById('lp'); if(lp) lp.value='';
};

window.addEventListener('beforeunload',()=>stopTimerDisplay());

window.changePass = async function(){
  const op=document.getElementById('old-pass').value, np=document.getElementById('new-pass2').value, al=document.getElementById('pass-alert');
  if(op!==CU.password){al.innerHTML='<div class="alert alert-err">Mevcut şifre hatalı.</div>';return;}
  if(np.length<4){al.innerHTML='<div class="alert alert-err">En az 4 karakter olmalı.</div>';return;}
  CU.password=np; await fsSet('pers',CU._id,CU);
  al.innerHTML='<div class="alert alert-ok">✔ Şifre güncellendi.</div>'; await logAct('Şifre değiştirildi.');
  setTimeout(()=>al.innerHTML='',2500);
};

function showPScreen(s){ document.querySelectorAll('.pscreen').forEach(e=>e.style.display='none'); const el=document.getElementById('screen-'+s); if(el) el.style.display='block'; }

async function showDash(){
  showPScreen('dash');
  document.getElementById('tn').textContent=CU.name;
  document.getElementById('tr').textContent=CU.rank+(CU.isAdmin?' · 🔴 ADMİN':'');
  buildSidebar(); showTab('home'); updateNotifCount(); checkAnnounceMode();
}

window.toggleTheme = function(){ darkMode=!darkMode; document.body.classList.toggle('light',!darkMode); const b=document.getElementById('theme-btn'); if(b) b.textContent=darkMode?'☀️ Aydınlık':'🌙 Karanlık'; };

async function addNotif(msg){ const n={id:Date.now().toString(),userId:CU._id,msg,time:new Date().toLocaleTimeString('tr-TR'),read:false}; await fsSet('notifs',n.id,n); updateNotifCount(); }
async function updateNotifCount(){ if(!CU) return; const all=await fsAll('notifs'); const n=all.filter(x=>x.userId===CU._id&&!x.read).length; const el=document.getElementById('nc'); if(el){el.style.display=n?'flex':'none';el.textContent=n;} }
window.toggleNotif = async function(){ const p=document.getElementById('notif-panel'); if(!p) return; const open=p.classList.toggle('open'); if(open){ const all=await fsAll('notifs'); const mine=all.filter(n=>n.userId===CU._id); for(const n of mine){if(!n.read){n.read=true;await fsSet('notifs',n._id,n);}} updateNotifCount(); document.getElementById('notif-list').innerHTML=mine.length?mine.slice().reverse().slice(0,20).map(n=>'<div class="notif-item"><div>'+n.msg+'</div><div class="notif-time">'+n.time+'</div></div>').join(''):'<div class="empty">Bildirim yok.</div>'; } };
window.clearNotifs = async function(){ const all=await fsAll('notifs'); for(const n of all.filter(x=>x.userId===CU._id)) await fsDel('notifs',n._id); updateNotifCount(); const p=document.getElementById('notif-panel'); if(p) p.classList.remove('open'); };

async function logAct(msg){ if(!CU) return; const e={id:Date.now().toString(),user:CU.name,rank:CU.rank,msg,time:new Date().toLocaleString('tr-TR')}; await fsSet('actlog',e.id,e); }
window.renderActLog = async function(){ const log=(await fsAll('actlog')).sort((a,b)=>b.id-a.id); const q=(document.getElementById('act-search')||{}).value||''; const f=q?log.filter(l=>(l.user+l.msg).toLowerCase().includes(q.toLowerCase())):log; document.getElementById('act-log-list').innerHTML=f.length?'<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Kullanıcı</th><th>Rütbe</th><th>İşlem</th><th>Zaman</th></tr></thead><tbody>'+f.map(l=>'<tr><td>'+l.user+'</td><td><span class="badge b-gold">'+l.rank+'</span></td><td style="color:var(--muted);font-size:11px">'+l.msg+'</td><td style="font-size:10px;color:var(--muted)">'+l.time+'</td></tr>').join('')+'</tbody></table></div>':'<div class="empty">Aktivite kaydı yok.</div>'; };

async function buildSidebar(){
  const isCmd=RL[CU.rank]>=RL['Sergeant I'], isHigh=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin;
  const [leaves,promos,applies,complaints,tickets]=await Promise.all([fsAll('leaves'),fsAll('promos'),fsAll('applies'),fsAll('complaints'),fsAll('tickets')]);
  const pL=leaves.filter(l=>l.status==='Bekliyor').length, pP=promos.filter(p=>p.status==='Bekliyor').length;
  const pA=applies.filter(a=>a.status==='Bekliyor').length, pC=complaints.filter(c=>c.status==='Bekliyor').length, pT=tickets.filter(t=>t.status==='Bekliyor').length;
  const sb=document.getElementById('sidebar'); sb.innerHTML='';
  const items=[{sec:'Genel'},{tab:'home',icon:'🏠',label:'Anasayfa'},{tab:'profile',icon:'👤',label:'Profilim'},{tab:'mesai',icon:'⏱',label:'Mesai'},{sec:'Birim'},{tab:'unit',icon:'👥',label:'Birimim'},{tab:'docs',icon:'📄',label:'Belgeler'},{tab:'dutylog',icon:'📋',label:'Görev Logu'}];
  if(isCmd){items.push({sec:'Komuta'});items.push({tab:'leave',icon:'🏖',label:'İzin',badge:pL});items.push({tab:'discipline',icon:'⚠️',label:'Disiplin'});items.push({tab:'promotion',icon:'⬆️',label:'Terfi',badge:pP});}
  if(isHigh){items.push({tab:'personnel',icon:'🗂',label:'Personel'});items.push({tab:'actlog',icon:'🔍',label:'Aktivite Logu'});}
  if(CU.isAdmin){items.push({sec:'Admin'});items.push({tab:'admin',icon:'🔴',label:'Admin Paneli',badge:(pA+pC+pT)||0});}
  items.forEach(item=>{
    if(item.sec){const s=document.createElement('div');s.className='sb-sec';s.textContent=item.sec;sb.appendChild(s);}
    else{const b=document.createElement('button');b.className='sb-btn';b.setAttribute('data-tab',item.tab);b.innerHTML=item.icon+' '+item.label+(item.badge?'<span class="sb-badge">'+item.badge+'</span>':'');b.onclick=()=>showTab(item.tab);sb.appendChild(b);}
  });
}

function showTab(t){
  if(t==='admin'&&!CU.isAdmin) return;
  document.querySelectorAll('.tab').forEach(e=>e.classList.remove('active'));
  document.querySelectorAll('.sb-btn').forEach(b=>b.classList.remove('active'));
  const el=document.getElementById('tab-'+t); if(el) el.classList.add('active');
  const btn=document.querySelector('[data-tab="'+t+'"]'); if(btn) btn.classList.add('active');
  const renders={home:renderHome,profile:renderProfile,mesai:renderMesai,unit:renderUnit,docs:renderDocs,leave:renderLeave,dutylog:renderDutyLog,discipline:renderDisc,promotion:renderPromo,personnel:renderPersonnel,actlog:window.renderActLog,admin:renderAdmin};
  if(renders[t]) renders[t]();
}
window.showTab = showTab;

async function renderHome(){
  const [pers,log,mesai]=await Promise.all([fsAll('pers'),fsAll('dutylog'),fsAll('mesai')]);
  const uid=CU._id, toplam=mesai.reduce((s,m)=>s+(m.sure||0),0);
  document.getElementById('sg').innerHTML=sc(pers.filter(p=>p.online).length,'Çevrimiçi')+sc(pers.length,'Toplam Personel')+sc(log.filter(l=>l.userId===uid).length,'Görevlerim')+sc(Math.round(toplam/60),'Toplam Mesai (s)');
  let items=[];
  if(CU.isAdmin){
    const [applies,complaints,tickets]=await Promise.all([fsAll('applies'),fsAll('complaints'),fsAll('tickets')]);
    applies.filter(a=>a.status==='Bekliyor').forEach(a=>items.push({text:a.name+' — başvuru',color:'b-gold'}));
    complaints.filter(c=>c.status==='Bekliyor').forEach(c=>items.push({text:c.name+' — şikayet',color:'b-red'}));
    tickets.filter(t=>t.status==='Bekliyor').forEach(t=>items.push({text:t.name+' — destek talebi',color:'b-blue'}));
  }
  const promos=await fsAll('promos');
  promos.filter(p=>p.status==='Bekliyor'&&(RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin)).forEach(p=>items.push({text:p.targetName+' — terfi teklifi',color:'b-warn'}));
  document.getElementById('pending-list').innerHTML=items.length?items.map(i=>'<div class="pcard" style="display:flex;align-items:center;gap:.75rem;margin-bottom:.5rem;padding:.75rem"><span class="badge '+i.color+'">●</span><span style="font-size:13px">'+i.text+'</span></div>').join(''):'<div class="empty">Bekleyen işlem yok.</div>';
  const actlog=(await fsAll('actlog')).sort((a,b)=>b.id-a.id).slice(0,8);
  document.getElementById('recent-act').innerHTML=actlog.length?actlog.map(l=>'<div style="display:flex;justify-content:space-between;padding:.5rem 0;border-bottom:1px solid var(--brown2);font-size:12px"><span style="color:var(--muted)">'+l.user+': '+l.msg+'</span><span style="color:var(--muted);font-size:10px">'+l.time+'</span></div>').join(''):'<div class="empty">Aktivite yok.</div>';
}
function sc(n,l){return '<div class="stat-card"><div class="stat-num">'+n+'</div><div class="stat-label">'+l+'</div></div>';}

async function renderMesai(){
  const mesai=await fsAll('mesai'), uid=CU._id;
  const aktif=mesai.find(m=>m.userId===uid&&m.bitis===null);
  const btn=document.getElementById('mesai-btn'), status=document.getElementById('mesai-status'), timer=document.getElementById('mesai-timer');
  if(aktif){if(btn){btn.textContent='Mesaiden Çık';btn.style.background='var(--danger)';btn.style.color='#fff';}if(status)status.innerHTML='<span class="badge b-green">● Mesaide</span>';mesaiStart=aktif.baslangic;startTimerDisplay();}
  else{if(btn){btn.textContent='Mesaiye Başla';btn.style.background='';btn.style.color='';}if(status)status.innerHTML='<span class="badge b-muted">● Dışarıda</span>';if(timer)timer.textContent='00:00:00';stopTimerDisplay();}
  const mine=mesai.filter(m=>m.userId===uid&&m.bitis!==null), toplamDk=mine.reduce((s,m)=>s+(m.sure||0),0);
  document.getElementById('mesai-toplam').textContent=Math.floor(toplamDk/60)+'s '+(toplamDk%60)+'dk';
  document.getElementById('mesai-list').innerHTML=mine.length?'<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Başlangıç</th><th>Bitiş</th><th>Süre</th></tr></thead><tbody>'+mine.slice().reverse().slice(0,20).map(m=>'<tr><td style="font-size:11px">'+m.baslangicStr+'</td><td style="font-size:11px">'+m.bitisStr+'</td><td><span class="badge b-gold">'+Math.floor(m.sure/60)+'s '+(m.sure%60)+'dk</span></td></tr>').join('')+'</tbody></table></div>':'<div class="empty">Mesai kaydı yok.</div>';
  const admSec=document.getElementById('mesai-admin-section'); if(admSec) admSec.style.display=(CU.isAdmin||RL[CU.rank]>=RL['Under Sheriff'])?'block':'none';
  renderMesaiAdmin();
}
window.startMesai = async function(){ const mesai=await fsAll('mesai'),uid=CU._id,aktif=mesai.find(m=>m.userId===uid&&m.bitis===null); if(aktif){endMesai();return;} const now=Date.now(),id=now.toString(); await fsSet('mesai',id,{id,userId:uid,userName:CU.name,rank:CU.rank,unit:CU.unit,baslangic:now,baslangicStr:new Date().toLocaleString('tr-TR'),bitis:null,bitisStr:null,sure:0}); mesaiStart=now; await logAct('Mesai başlatıldı.'); await addNotif('Mesai başlatıldı.'); renderMesai(); };
async function endMesai(){ const mesai=await fsAll('mesai'),uid=CU._id,aktif=mesai.find(m=>m.userId===uid&&m.bitis===null); if(!aktif) return; const now=Date.now(),sure=Math.round((now-aktif.baslangic)/60000); aktif.bitis=now;aktif.bitisStr=new Date().toLocaleString('tr-TR');aktif.sure=sure; await fsSet('mesai',aktif._id,aktif); mesaiStart=null;stopTimerDisplay(); await logAct('Mesai sonlandırıldı: '+Math.floor(sure/60)+'s '+(sure%60)+'dk'); await addNotif('Mesai sonlandırıldı: '+Math.floor(sure/60)+'s '+(sure%60)+'dk'); renderMesai(); }
function startTimerDisplay(){ stopTimerDisplay(); mesaiTimer=setInterval(()=>{const t=document.getElementById('mesai-timer');if(!t||!mesaiStart)return;const d=Math.floor((Date.now()-mesaiStart)/1000),h=Math.floor(d/3600),m=Math.floor((d%3600)/60),s=d%60;t.textContent=(h<10?'0':'')+h+':'+(m<10?'0':'')+m+':'+(s<10?'0':'')+s;},1000); }
function stopTimerDisplay(){ if(mesaiTimer){clearInterval(mesaiTimer);mesaiTimer=null;} }
async function renderMesaiAdmin(){ const el=document.getElementById('mesai-admin-list');if(!el)return; const [mesai,pers]=await Promise.all([fsAll('mesai'),fsAll('pers')]); const ozet={}; pers.forEach(p=>{const uid=p._id,mine=mesai.filter(m=>m.userId===uid),aktif=mine.find(m=>m.bitis===null),toplamDk=mine.filter(m=>m.bitis!==null).reduce((s,m)=>s+(m.sure||0),0);ozet[uid]={name:p.name,rank:p.rank,unit:p.unit,toplam:toplamDk,aktif:!!aktif};}); const sorted=Object.values(ozet).sort((a,b)=>b.toplam-a.toplam); el.innerHTML='<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Personel</th><th>Rütbe</th><th>Birim</th><th>Toplam Mesai</th><th>Durum</th></tr></thead><tbody>'+sorted.map(p=>'<tr><td><b>'+p.name+'</b></td><td><span class="badge b-gold">'+p.rank+'</span></td><td style="font-size:11px;color:var(--muted)">'+p.unit+'</td><td><span class="badge b-blue">'+Math.floor(p.toplam/60)+'s '+(p.toplam%60)+'dk</span></td><td>'+(p.aktif?'<span class="badge b-green">● Mesaide</span>':'<span class="badge b-muted">Dışarıda</span>')+'</td></tr>').join('')+'</tbody></table></div>'; }

function renderAdmin(){ if(!CU.isAdmin) return; adminTab(curAdminTab,null); }
window.renderAdmin = renderAdmin;

window.adminTab = function(t,btn){
  curAdminTab=t;
  ['applies','complaints','praises','tickets','personnel','hq','galeri','dm','settings'].forEach(x=>{const el=document.getElementById('adm-'+x);if(el)el.style.display=(x===t?'block':'none');});
  document.querySelectorAll('#tab-admin .tab-sw-btn').forEach(b=>b.classList.remove('active'));
  if(btn) btn.classList.add('active');
  else{const tList=['applies','complaints','praises','tickets','personnel','hq','galeri','dm','settings'],all=document.querySelectorAll('#tab-admin .tab-sw-btn'),idx=tList.indexOf(t);if(all[idx])all[idx].classList.add('active');}
  if(t==='applies') renderAdminApplies();
  if(t==='complaints') renderAdminComplaints();
  if(t==='praises') renderAdminPraises();
  if(t==='tickets') renderAdminTickets();
  if(t==='personnel'){renderAdminPersonnel();fillAdminRankSelect('a-nr');}
  if(t==='hq') renderAdminHQ();
  if(t==='galeri') renderAdminGallery();
  if(t==='dm') renderAdminDM();
  if(t==='settings') renderAdminSettings();
};

async function renderAdminApplies(){ const applies=(await fsAll('applies')).sort((a,b)=>a.status==='Bekliyor'?-1:1); const el=document.getElementById('adm-applies-list');if(!el)return; if(!applies.length){el.innerHTML='<div class="empty">Henüz başvuru yok.</div>';return;} el.innerHTML=applies.map(a=>{const sb=a.status==='Onaylandı'?'<span class="badge b-green">Onaylandı</span>':a.status==='Reddedildi'?'<span class="badge b-red">Reddedildi</span>':'<span class="badge b-warn">Bekliyor</span>',act=a.status==='Bekliyor'?'<button class="act-btn green" onclick="approveApply(\''+a._id+'\')">Onayla</button><button class="act-btn red" onclick="rejectApply(\''+a._id+'\')">Reddet</button>':'';return '<div class="pcard" style="margin-bottom:.75rem"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.75rem"><div style="font-family:\'Bebas Neue\',sans-serif;font-size:18px">'+a.name+'</div><div style="display:flex;gap:6px">'+sb+act+'</div></div><div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:.5rem;margin-bottom:.5rem"><div><div class="pi-lbl">Discord</div><div style="font-size:12px;color:var(--gold)">'+(a.discord||'-')+'</div></div><div><div class="pi-lbl">Birim</div><div style="font-size:12px">'+(a.unit||'-')+'</div></div><div><div class="pi-lbl">Deneyim</div><div style="font-size:12px">'+(a.experience||'-')+'</div></div></div><div style="background:var(--bg3);border-radius:4px;padding:.6rem;font-size:12px;color:var(--muted)"><b style="color:var(--text)">Neden BCSO:</b> '+(a.reason||'-')+'</div><div style="font-size:10px;color:var(--muted);margin-top:.5rem">📅 '+a.date+'</div></div>';}).join('');}
window.approveApply = async function(id){ const a=await fsGet('applies',id);if(!a)return;a.status='Onaylandı';a.reviewedBy=CU.name;await fsSet('applies',id,a);await logAct('Başvuru onaylandı: '+a.name);await addNotif(a.name+' başvurusu onaylandı ✔');renderAdminApplies();buildSidebar(); };
window.rejectApply  = async function(id){ const a=await fsGet('applies',id);if(!a)return;a.status='Reddedildi';a.reviewedBy=CU.name;await fsSet('applies',id,a);await logAct('Başvuru reddedildi: '+a.name);renderAdminApplies();buildSidebar(); };

async function renderAdminComplaints(){ const complaints=(await fsAll('complaints')).sort((a,b)=>a.status==='Bekliyor'?-1:1); const el=document.getElementById('adm-complaints-list');if(!el)return; if(!complaints.length){el.innerHTML='<div class="empty">Şikayet yok.</div>';return;} el.innerHTML=complaints.map(c=>{const sb=c.status==='İncelendi'?'<span class="badge b-green">İncelendi</span>':c.status==='Reddedildi'?'<span class="badge b-muted">Reddedildi</span>':'<span class="badge b-red">Bekliyor</span>',act=c.status==='Bekliyor'?'<button class="act-btn green" onclick="approveComplaint(\''+c._id+'\')">İncele</button><button class="act-btn red" onclick="rejectComplaint(\''+c._id+'\')">Reddet</button>':'';return '<div class="pcard" style="margin-bottom:.75rem"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.75rem"><div><div style="font-family:\'Bebas Neue\',sans-serif;font-size:16px">'+c.name+'</div><div style="font-size:11px;color:var(--muted)">Şikayet: <b style="color:var(--danger)">'+c.target+'</b></div></div><div style="display:flex;gap:6px">'+sb+act+'</div></div><div style="background:var(--bg3);border-radius:4px;padding:.6rem;font-size:12px;color:var(--muted)"><b style="color:var(--text)">Açıklama:</b> '+(c.desc||'-')+'</div><div style="font-size:10px;color:var(--muted);margin-top:.4rem">📅 '+c.submitDate+'</div></div>';}).join('');}
window.approveComplaint = async function(id){ const c=await fsGet('complaints',id);if(!c)return;c.status='İncelendi';c.reviewedBy=CU.name;await fsSet('complaints',id,c);await logAct('Şikayet incelendi.');renderAdminComplaints();buildSidebar(); };
window.rejectComplaint  = async function(id){ const c=await fsGet('complaints',id);if(!c)return;c.status='Reddedildi';c.reviewedBy=CU.name;await fsSet('complaints',id,c);await logAct('Şikayet reddedildi.');renderAdminComplaints();buildSidebar(); };

async function renderAdminPraises(){ const praises=await fsAll('praises'); const el=document.getElementById('adm-praises-list');if(!el)return; el.innerHTML=praises.length?praises.map(p=>'<div class="pcard" style="margin-bottom:.75rem"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><div><b>'+p.name+'</b> → <span style="color:var(--success)">'+p.target+'</span></div><span class="badge b-green">✔</span></div><div style="background:var(--bg3);border-radius:4px;padding:.6rem;font-size:12px;color:var(--muted)">'+p.desc+'</div><div style="font-size:10px;color:var(--muted);margin-top:.4rem">📅 '+p.date+'</div></div>').join(''):'<div class="empty">Övgü yok.</div>';}

async function renderAdminTickets(){ const tickets=(await fsAll('tickets')).sort((a,b)=>a.status==='Bekliyor'?-1:1); const el=document.getElementById('adm-tickets-list');if(!el)return; if(!tickets.length){el.innerHTML='<div class="empty">Destek talebi yok.</div>';return;} el.innerHTML=tickets.map(t=>{const sb=t.status==='Yanıtlandı'?'<span class="badge b-green">Yanıtlandı</span>':t.status==='Kapatıldı'?'<span class="badge b-muted">Kapatıldı</span>':'<span class="badge b-blue">Bekliyor</span>',rb=t.status==='Bekliyor'?'<div style="margin-top:.75rem;display:flex;gap:.5rem"><input type="text" id="treply-'+t._id+'" placeholder="Yanıt yazın..." style="flex:1;background:var(--bg3);border:1px solid var(--brown);border-radius:4px;padding:7px 10px;color:var(--text);font-size:12px;outline:none"><button class="act-btn green" onclick="replyTicket(\''+t._id+'\')">Yanıtla</button><button class="act-btn red" onclick="closeTicket(\''+t._id+'\')">Kapat</button></div>':(t.reply?'<div style="margin-top:.5rem;background:rgba(106,170,90,.08);border:1px solid rgba(106,170,90,.2);border-radius:4px;padding:.6rem;font-size:12px"><b style="color:var(--success)">Yanıt:</b> '+t.reply+'</div>':'');return '<div class="pcard" style="margin-bottom:.75rem"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><div><span class="badge b-blue" style="margin-right:.5rem">'+(t.category||'Genel')+'</span><b>'+t.subject+'</b><div style="font-size:11px;color:var(--muted);margin-top:2px">'+t.name+(t.discord?' · '+t.discord:'')+'</div></div>'+sb+'</div><div style="background:var(--bg3);border-radius:4px;padding:.6rem;font-size:12px;color:var(--muted)">'+t.desc+'</div><div style="font-size:10px;color:var(--muted);margin-top:.4rem">📅 '+t.date+'</div>'+rb+'</div>';}).join('');}
window.replyTicket = async function(id){ const inp=document.getElementById('treply-'+id);if(!inp||!inp.value.trim())return; const t=await fsGet('tickets',id);if(!t)return;t.status='Yanıtlandı';t.reply=inp.value.trim();t.repliedBy=CU.name;await fsSet('tickets',id,t);await logAct('Ticket yanıtlandı.');await addNotif('Ticket yanıtlandı: '+t.subject);renderAdminTickets();buildSidebar(); };
window.closeTicket  = async function(id){ const t=await fsGet('tickets',id);if(!t)return;t.status='Kapatıldı';t.closedBy=CU.name;await fsSet('tickets',id,t);await logAct('Ticket kapatıldı.');renderAdminTickets();buildSidebar(); };

window.addHQPost = async function(){ const title=(document.getElementById('hq-title')||{}).value||'',content=(document.getElementById('hq-content-inp')||{}).value||'',imgUrl=(document.getElementById('hq-img-url')||{}).value||'',type=(document.getElementById('hq-type')||{}).value||'haber'; if(!title.trim()||!content.trim()){alert('Başlık ve içerik zorunludur.');return;} const id=Date.now().toString(); await fsSet('hq',id,{id,title:title.trim(),content:content.trim(),imgUrl:imgUrl.trim(),type,author:CU.name,date:new Date().toLocaleDateString('tr-TR')}); await logAct('HQ haberi: '+title);await addNotif('Yeni HQ haberi: '+title); ['hq-title','hq-content-inp','hq-img-url'].forEach(x=>{const e=document.getElementById(x);if(e)e.value='';}); renderAdminHQ();alert('✔ Yayınlandı!'); };
async function renderAdminHQ(){ const posts=(await fsAll('hq')).sort((a,b)=>b.id-a.id); const el=document.getElementById('adm-hq-list');if(!el)return; el.innerHTML=posts.length?posts.map(p=>'<div class="pcard" style="margin-bottom:.5rem;display:flex;justify-content:space-between;align-items:center"><div><span class="badge b-gold" style="margin-right:.5rem">'+p.type+'</span><b>'+p.title+'</b><div style="font-size:10px;color:var(--muted)">'+p.author+' · '+p.date+'</div></div><button class="act-btn red" onclick="deleteHQPost(\''+p._id+'\')">Sil</button></div>').join(''):'<div class="empty">Haber yok.</div>';}
window.deleteHQPost = async function(id){ if(!confirm('Bu haberi silmek istiyor musunuz?'))return; await fsDel('hq',id);await logAct('HQ haberi silindi.');renderAdminHQ(); };

window.addGalleryPhoto = async function(){ const url=(document.getElementById('gal-url')||{}).value||'',title=(document.getElementById('gal-title')||{}).value||'',desc=(document.getElementById('gal-desc')||{}).value||''; if(!url.trim()){alert('Görsel URL zorunludur.');return;} const id=Date.now().toString(); await fsSet('gallery',id,{id,url:url.trim(),title:title.trim(),desc:desc.trim(),author:CU.name,date:new Date().toLocaleDateString('tr-TR')}); await logAct('Galeriye fotoğraf eklendi.');await addNotif('Galeriye yeni fotoğraf eklendi'); ['gal-url','gal-title','gal-desc'].forEach(x=>{const e=document.getElementById(x);if(e)e.value='';}); renderAdminGallery();alert('✔ Eklendi!'); };
async function renderAdminGallery(){ const photos=(await fsAll('gallery')).sort((a,b)=>b.id-a.id); const el=document.getElementById('adm-gallery-list');if(!el)return; el.innerHTML=photos.length?photos.map(p=>'<div style="position:relative;background:var(--bg3);border:1px solid var(--brown);border-radius:8px;overflow:hidden"><img src="'+p.url+'" style="width:100%;height:140px;object-fit:cover"><div style="padding:.6rem"><div style="font-size:12px;font-weight:600">'+p.title+'</div><div style="font-size:10px;color:var(--muted)">'+p.author+' · '+p.date+'</div></div><button class="act-btn red" onclick="deleteGalleryPhoto(\''+p._id+'\')" style="position:absolute;top:4px;right:4px">✕</button></div>').join(''):'<div style="color:var(--muted);font-size:12px;padding:1rem">Fotoğraf yok.</div>';}
window.deleteGalleryPhoto = async function(id){ if(!confirm('Silmek istiyor musunuz?'))return; await fsDel('gallery',id);await logAct('Galeri fotoğrafı silindi.');renderAdminGallery(); };

window.adminSetPhoto = async function(id){ const url=prompt('Personel fotoğraf URL (boş = temizle):');if(url===null)return; const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return; p.photo=url.trim();await fsSet('pers',p._id,p);await logAct(p.name+' fotoğrafı güncellendi.');renderAdminPersonnel();alert('✔ Güncellendi!'); };

async function renderAdminPersonnel(){ const [pers,mesai]=await Promise.all([fsAll('pers'),fsAll('mesai')]); const el=document.getElementById('adm-personnel-list');if(!el)return; const q=(document.getElementById('adm-pers-search')||{}).value||''; let p2=q?pers.filter(p=>(p.name+p.rank+p.unit).toLowerCase().includes(q.toLowerCase())):pers; p2=p2.slice().sort((a,b)=>RL[b.rank]-RL[a.rank]); const groups={}; p2.forEach(p=>{if(!groups[p.rank])groups[p.rank]=[];groups[p.rank].push(p);}); let html=''; RANKS.slice().reverse().forEach(rank=>{if(!groups[rank]||!groups[rank].length)return; html+='<div style="margin-bottom:1.5rem"><div style="display:flex;align-items:center;gap:.75rem;margin-bottom:.75rem"><div style="font-family:\'Bebas Neue\',sans-serif;font-size:22px;color:var(--gold)">'+rank+'</div><span class="badge b-muted">'+groups[rank].length+'</span></div><div class="tbl-wrap"><table class="tbl"><thead><tr><th>İsim</th><th>Birim</th><th>Rozet</th><th>Uyarı</th><th>Durum</th><th>İşlem</th></tr></thead><tbody>'+groups[rank].map(p=>{const pid=p._id;return '<tr><td><b>'+p.name+'</b>'+(p.isAdmin?' <span class="badge b-red" style="font-size:9px">ADMIN</span>':'')+'</td><td style="font-size:11px;color:var(--muted)">'+p.unit+'</td><td><span class="badge b-muted">'+p.badge+'</span></td><td><span class="badge '+(p.warns?'b-red':'b-muted')+'">'+(p.warns||0)+'</span></td><td>'+(p.online?'<span class="badge b-green">Aktif</span>':'<span class="badge b-muted">Pasif</span>')+'</td><td style="white-space:nowrap"><button class="act-btn" onclick="adminEditRank(\''+pid+'\')">Rütbe</button><button class="act-btn" onclick="adminEditUnit(\''+pid+'\')">Birim</button><button class="act-btn" onclick="adminSetPhoto(\''+pid+'\')">📷</button><button class="act-btn" onclick="adminChangePass(\''+pid+'\')">Şifre</button><button class="act-btn '+(p.isAdmin?'red':'')+'" onclick="toggleAdminRole(\''+pid+'\')">'+(p.isAdmin?'Admin Al':'Admin Ver')+'</button><button class="act-btn red" onclick="adminDelPers(\''+pid+'\')">Sil</button></td></tr>';}).join('')+'</tbody></table></div></div>';});  el.innerHTML=html||'<div class="empty">Personel bulunamadı.</div>';}
window.adminEditRank    = async function(id){ const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return;const nr=prompt('Yeni rütbe:\n'+RANKS.join(', '),p.rank);if(!nr||!RANKS.includes(nr)){if(nr)alert('Geçersiz rütbe!');return;}p.rank=nr;await fsSet('pers',id,p);await logAct(p.name+' rütbesi → '+nr);renderAdminPersonnel(); };
window.adminEditUnit    = async function(id){ const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return;const nu=prompt('Yeni birim:\n'+UNITS.join(', '),p.unit);if(!nu||!UNITS.includes(nu)){if(nu)alert('Geçersiz birim!');return;}p.unit=nu;await fsSet('pers',id,p);await logAct(p.name+' birimi → '+nu);renderAdminPersonnel(); };
window.adminChangePass  = async function(id){ const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return;const np=prompt(p.name+' için yeni şifre:');if(!np||np.length<4){if(np)alert('En az 4 karakter.');return;}p.password=np;await fsSet('pers',id,p);await logAct('Şifre değiştirildi: '+p.name);alert('✔ Güncellendi.'); };
window.adminDelPers     = async function(id){ if(!confirm('Bu personeli silmek istiyor musunuz?'))return; await fsDel('pers',id);await logAct('Personel silindi.');renderAdminPersonnel(); };
window.toggleAdminRole  = async function(id){ const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return;if(p._id===CU._id){alert('Kendi yetkinizi değiştiremezsiniz.');return;}p.isAdmin=!p.isAdmin;await fsSet('pers',id,p);await logAct((p.isAdmin?'Admin verildi: ':'Admin alındı: ')+p.name);await addNotif(p.name+(p.isAdmin?' admin oldu ✔':' admin yetkisi alındı'));alert('✔ '+p.name+(p.isAdmin?' admin oldu.':' admin yetkisi alındı.'));renderAdminPersonnel(); };
function fillAdminRankSelect(selId){ const sel=document.getElementById(selId);if(!sel||sel.options.length)return;sel.innerHTML=RANKS.map(r=>'<option>'+r+'</option>').join('');}
window.fillAdminRankSelect = fillAdminRankSelect;

window.createPersonnelAdmin = async function(){ const u=document.getElementById('a-nu').value.trim(),n=document.getElementById('a-nn').value.trim(),p=document.getElementById('a-np').value.trim(),r=document.getElementById('a-nr').value,unit=document.getElementById('a-nunit').value,badge=document.getElementById('a-nbadge').value.trim(),disc=document.getElementById('a-ndisc').value.trim(),al=document.getElementById('adm-pers-alert'); if(!u||!n||!p||!badge){if(al)al.innerHTML='<div class="alert alert-err">Tüm alanları doldurun.</div>';return;} const pers=await fsAll('pers');if(pers.find(x=>x.username===u)){if(al)al.innerHTML='<div class="alert alert-err">Bu kullanıcı adı zaten var.</div>';return;} const id=u+'_'+Date.now(); await fsSet('pers',id,{id,username:u,password:p,name:n,rank:r,unit,badge,discord:disc,online:false,warns:0,duties:0,isAdmin:false,photo:''}); await logAct('Personel oluşturuldu: '+n);await addNotif('Yeni personel: '+n); if(al){al.innerHTML='<div class="alert alert-ok">✔ '+n+' oluşturuldu.</div>';setTimeout(()=>al.innerHTML='',2500);} ['a-nu','a-nn','a-np','a-nbadge','a-ndisc'].forEach(x=>{const e=document.getElementById(x);if(e)e.value='';}); renderAdminPersonnel(); };
window.createPersonnelTab  = async function(){ const u=document.getElementById('p-nu').value.trim(),n=document.getElementById('p-nn').value.trim(),p=document.getElementById('p-np').value.trim(),r=document.getElementById('p-nr').value,unit=document.getElementById('p-nunit').value,badge=document.getElementById('p-nbadge').value.trim(),disc=document.getElementById('p-ndisc').value.trim(),al=document.getElementById('pers-alert-tab'); if(!u||!n||!p||!badge){if(al)al.innerHTML='<div class="alert alert-err">Tüm alanları doldurun.</div>';return;} const pers=await fsAll('pers');if(pers.find(x=>x.username===u)){if(al)al.innerHTML='<div class="alert alert-err">Bu kullanıcı adı zaten var.</div>';return;} const id=u+'_'+Date.now(); await fsSet('pers',id,{id,username:u,password:p,name:n,rank:r,unit,badge,discord:disc,online:false,warns:0,duties:0,isAdmin:false,photo:''}); await logAct('Personel oluşturuldu: '+n); if(al){al.innerHTML='<div class="alert alert-ok">✔ '+n+' oluşturuldu.</div>';setTimeout(()=>al.innerHTML='',2500);} ['p-nu','p-nn','p-np','p-nbadge','p-ndisc'].forEach(x=>{const e=document.getElementById(x);if(e)e.value='';}); renderPersonnel(); };

let dmTarget=null;
async function renderAdminDM(){ const pers=(await fsAll('pers')).filter(p=>p._id!==CU._id); const dms=await fsAll('dm'); const leftHTML=pers.map(p=>{const msgs=dms.filter(m=>m.convId===p._id),unread=msgs.filter(m=>!m.read&&m.from!==CU._id).length,last=msgs.length?msgs[msgs.length-1]:null,active=dmTarget&&dmTarget._id===p._id;return '<div onclick="selectDMTarget(\''+p._id+'\')" style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-bottom:1px solid var(--brown2);cursor:pointer;background:'+(active?'rgba(232,184,75,.08)':'transparent')+'"><div style="width:36px;height:36px;border-radius:50%;background:var(--brown2);border:1px solid var(--brown);display:flex;align-items:center;justify-content:center;font-family:\'Bebas Neue\',sans-serif;font-size:13px;color:var(--gold);flex-shrink:0">'+p.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase()+'</div><div style="flex:1;min-width:0"><div style="display:flex;justify-content:space-between"><span style="font-size:13px;font-weight:600">'+p.name+'</span>'+(unread?'<span style="background:var(--danger);color:#fff;border-radius:50%;width:18px;height:18px;font-size:10px;display:flex;align-items:center;justify-content:center">'+unread+'</span>':'')+'</div><div style="font-size:11px;color:var(--muted)">'+(last?last.text.slice(0,30):'<i>Mesaj yok</i>')+'</div></div></div>';}).join(''); let rightHTML; if(!dmTarget){rightHTML='<div style="display:flex;align-items:center;justify-content:center;height:300px;color:var(--muted)">← Soldan personel seçin</div>';}else{const msgs=dms.filter(m=>m.convId===dmTarget._id),msgsHTML=msgs.map(m=>{const mine=m.from===CU._id;return '<div style="display:flex;flex-direction:column;align-items:'+(mine?'flex-end':'flex-start')+';margin-bottom:10px"><div style="font-size:10px;color:var(--muted);margin-bottom:3px">'+(mine?'Siz':dmTarget.name)+' · '+m.time+'</div><div style="max-width:75%;background:'+(mine?'rgba(232,184,75,.15)':'var(--bg3)')+';border:1px solid '+(mine?'rgba(232,184,75,.3)':'var(--brown)')+';border-radius:8px;padding:8px 12px;font-size:13px">'+m.text+'</div></div>';}).join('');rightHTML='<div style="display:flex;flex-direction:column;height:340px"><div style="padding:10px 14px;border-bottom:1px solid var(--brown)"><b>'+dmTarget.name+'</b> <span style="font-size:10px;color:var(--muted)">'+dmTarget.rank+'</span></div><div id="dm-msgs" style="flex:1;overflow-y:auto;padding:12px">'+(msgsHTML||'<div style="text-align:center;color:var(--muted);margin-top:2rem;font-size:12px">Henüz mesaj yok.</div>')+'</div><div style="display:flex;gap:8px;padding:10px;border-top:1px solid var(--brown)"><input id="dm-inp" type="text" placeholder="Mesaj yaz..." style="flex:1;background:var(--bg3);border:1px solid var(--brown);border-radius:4px;padding:8px 12px;color:var(--text);font-size:13px;outline:none" onkeydown="if(event.key===\'Enter\')sendDM()"><button onclick="sendDM()" style="background:var(--gold);color:#0d0a07;border:none;border-radius:4px;padding:8px 16px;font-weight:700;font-size:12px;cursor:pointer">Gönder</button></div></div>';} document.getElementById('adm-dm').innerHTML='<div style="display:grid;grid-template-columns:240px 1fr;border:1px solid var(--brown);border-radius:8px;overflow:hidden;background:var(--bg2)"><div style="border-right:1px solid var(--brown);overflow-y:auto;max-height:400px"><div style="padding:10px 12px;border-bottom:1px solid var(--brown);font-size:10px;color:var(--gold);letter-spacing:2px;text-transform:uppercase">Personel</div>'+leftHTML+'</div><div>'+rightHTML+'</div></div>'; setTimeout(()=>{const m=document.getElementById('dm-msgs');if(m)m.scrollTop=m.scrollHeight;},50); }
window.selectDMTarget = async function(id){ const pers=await fsAll('pers');dmTarget=pers.find(p=>p._id===id);renderAdminDM();buildSidebar(); };
window.sendDM = async function(){ const inp=document.getElementById('dm-inp');if(!inp||!inp.value.trim()||!dmTarget)return; const id=Date.now().toString(); await fsSet('dm',id,{id,convId:dmTarget._id,from:CU._id,fromName:CU.name,to:dmTarget._id,text:inp.value.trim(),time:new Date().toLocaleTimeString('tr-TR',{hour:'2-digit',minute:'2-digit'}),read:false}); await addNotif(dmTarget.name+" 'e DM gönderildi.");await logAct('DM: '+dmTarget.name);inp.value='';renderAdminDM(); };

async function renderAdminSettings(){ const mode=await fsGet('settings','announceMode')||{active:false,message:''}; const el=document.getElementById('adm-announce-status');if(el)el.textContent=mode.active?'✔ Aktif':'Pasif'; const msgEl=document.getElementById('adm-announce-msg');if(msgEl)msgEl.value=mode.message||'';}
window.toggleAnnounceMode = async function(){ const mode=await fsGet('settings','announceMode')||{active:false,message:''},msg=(document.getElementById('adm-announce-msg')||{}).value||'';mode.active=!mode.active;mode.message=msg;await fsSet('settings','announceMode',mode);await logAct('Duyuru modu '+(mode.active?'açıldı':'kapatıldı')+'.');renderAdminSettings();checkAnnounceMode(); };
window.saveAnnounceMsg = async function(){ const msg=(document.getElementById('adm-announce-msg')||{}).value||'',mode=await fsGet('settings','announceMode')||{active:false,message:''};mode.message=msg;await fsSet('settings','announceMode',mode);await logAct('Duyuru mesajı güncellendi.');checkAnnounceMode();alert('✔ Güncellendi.'); };
window.adminClearLog = async function(){ if(!confirm('Tüm aktivite logları silinecek?'))return; const log=await fsAll('actlog');for(const l of log)await fsDel('actlog',l._id);alert('✔ Temizlendi.'); };
window.adminResetAll = async function(){ if(!confirm('⚠️ TÜM VERİLER SİFİRLANACAK!'))return;if(!confirm('Son uyarı!'))return; const cols=['pers','docs','leaves','promos','warns','duties','dutylog','actlog','chat','notifs','applies','complaints','praises','tickets','mesai','hq','gallery','dm','settings'];for(const c of cols){const items=await fsAll(c);for(const item of items)await fsDel(c,item._id);}alert('Sıfırlandı.');location.reload(); };
async function checkAnnounceMode(){ const mode=await fsGet('settings','announceMode')||{active:false,message:''}; const ex=document.getElementById('announce-banner');if(ex)ex.remove(); if(mode.active&&mode.message){const b=document.createElement('div');b.id='announce-banner';b.style.cssText='background:rgba(200,146,42,0.15);border-bottom:2px solid var(--gold);padding:.75rem 1.5rem;font-size:13px;color:var(--gold);text-align:center;font-weight:600;letter-spacing:1px;';b.textContent='📢 '+mode.message;const t=document.querySelector('.topbar');if(t)t.insertAdjacentElement('afterend',b);} }

async function renderProfile(){ const ini=CU.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase(); const pavEl=document.getElementById('pav');if(pavEl)pavEl.textContent=ini; const pavImg=document.getElementById('pav-img'); if(pavImg){const me=await fsGet('pers',CU._id);if(me&&me.photo){pavImg.src=me.photo;pavImg.style.display='block';if(pavEl)pavEl.textContent='';}else{pavImg.style.display='none';if(pavEl)pavEl.textContent=ini;}} document.getElementById('pname').textContent=CU.name; document.getElementById('pmeta').textContent=CU.rank+' • '+CU.unit+' • '+CU.badge; document.getElementById('pi-rank').textContent=CU.rank; document.getElementById('pi-unit').textContent=CU.unit; document.getElementById('pi-badge').textContent=CU.badge; document.getElementById('pi-discord').textContent=CU.discord||'-'; const warns=await fsAll('warns'); document.getElementById('pi-warns').textContent=warns.filter(w=>w.targetId===CU._id).length; const log=await fsAll('dutylog'); document.getElementById('pi-duties').textContent=log.filter(l=>l.userId===CU._id).length; const prog=Math.min(100,Math.round((RL[CU.rank]/(RANKS.length-1))*100)); document.getElementById('rank-prog').style.width=prog+'%'; document.getElementById('rank-prog-label').textContent='Rütbe ilerlemesi: '+CU.rank+' ('+prog+'%)'; const docs=await fsAll('docs');const myDocs=docs.filter(d=>d.targetId===CU._id); document.getElementById('my-docs-list').innerHTML=myDocs.length?myDocs.map(d=>docRow(d)).join(''):'<div class="empty">Belge yok.</div>'; renderMyDMs(); }

function renderUnit(){ document.getElementById('unit-title').textContent=CU.unit; unitTab(curUnitTab,null); }
window.renderUnit = renderUnit;
window.unitTab = function(t,btn){ curUnitTab=t; ['members','stats','announce','chat','duties'].forEach(x=>{const el=document.getElementById('unit-'+x);if(el)el.style.display=(x===t?'block':'none');}); document.querySelectorAll('#tab-unit .tab-sw-btn').forEach(b=>b.classList.remove('active'));if(btn)btn.classList.add('active'); if(t==='members')renderUnitMembers();if(t==='stats')renderUnitStats();if(t==='announce')renderAnnounce();if(t==='chat')renderChat();if(t==='duties')renderDuties(); };
async function renderUnitMembers(){ const pers=(await fsAll('pers')).filter(p=>p.unit===CU.unit).sort((a,b)=>RL[b.rank]-RL[a.rank]); document.getElementById('unit-tbody').innerHTML=pers.map(p=>'<tr><td>'+p.name+'</td><td><span class="badge b-gold">'+p.rank+'</span></td><td><span class="badge b-muted">'+p.badge+'</span></td><td>'+(p.duties||0)+'</td><td>'+(p.online?'<span class="badge b-green">Aktif</span>':'<span class="badge b-muted">Pasif</span>')+'</td></tr>').join(''); }
async function renderUnitStats(){ const pers=(await fsAll('pers')).filter(p=>p.unit===CU.unit),log=await fsAll('dutylog'),unitLog=log.filter(l=>pers.find(p=>p._id===l.userId)); const sg=document.getElementById('unit-stat-grid');if(!sg)return; sg.innerHTML=sc(pers.length,'Üye Sayısı')+sc(pers.filter(p=>p.online).length,'Aktif Üye')+sc(unitLog.length,'Toplam Görev')+sc(pers.reduce((s,p)=>s+(p.warns||0),0),'Toplam Uyarı'); }
async function renderAnnounce(){ const isCmd=RL[CU.rank]>=RL['Sergeant I']||CU.isAdmin; const form=document.getElementById('unit-ann-form');if(form)form.style.display=isCmd?'block':'none'; const anns=(await fsAll('announce')).filter(a=>a.unit===CU.unit).sort((a,b)=>b.id-a.id); document.getElementById('ann-list').innerHTML=anns.length?anns.map(a=>'<div class="pcard" style="margin-bottom:.5rem"><div style="font-weight:600;margin-bottom:.3rem">'+a.title+'</div><div style="font-size:12px;color:var(--muted)">'+a.content+'</div><div style="font-size:10px;color:var(--muted);margin-top:.4rem">'+a.author+' · '+a.date+'</div></div>').join(''):'<div class="empty">Duyuru yok.</div>'; }
window.postAnnounce = async function(){ const title=document.getElementById('ann-title').value.trim(),content=document.getElementById('ann-content').value.trim(); if(!title||!content){alert('Boş olamaz.');return;} const id=Date.now().toString(); await fsSet('announce',id,{id,unit:CU.unit,title,content,author:CU.name,date:new Date().toLocaleDateString('tr-TR')}); await logAct('Duyuru: '+title); document.getElementById('ann-title').value='';document.getElementById('ann-content').value='';renderAnnounce(); };
async function renderChat(){ const chats=(await fsAll('chat')).filter(m=>m.unit===CU.unit).sort((a,b)=>a.id-b.id); const el=document.getElementById('chat-msgs');if(!el)return; el.innerHTML=chats.map(m=>{const mine=m.userId===CU._id;return '<div class="chat-msg'+(mine?' mine':'')+'"><div class="chat-sender">'+m.sender+'</div><div class="chat-bubble">'+m.text+'</div></div>';}).join(''); el.scrollTop=el.scrollHeight; }
window.sendChat = async function(){ const inp=document.getElementById('chat-inp');if(!inp||!inp.value.trim())return; const id=Date.now().toString(); await fsSet('chat',id,{id,unit:CU.unit,userId:CU._id,sender:CU.name,text:inp.value.trim(),time:new Date().toLocaleTimeString('tr-TR')}); inp.value='';renderChat(); };
async function renderDuties(){ const duties=(await fsAll('duties')).filter(d=>d.unit===CU.unit); document.getElementById('duty-list').innerHTML=duties.length?duties.map(d=>'<div class="pcard" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><div><b>'+d.type+'</b> <span style="color:var(--muted);font-size:12px">— '+d.loc+'</span><br><span style="font-size:11px;color:var(--muted)">'+d.author+' · '+d.time+'</span></div><button class="act-btn red" onclick="endDuty(\''+d._id+'\')">Bitir</button></div>').join(''):'<div class="empty">Aktif görev yok.</div>'; }
window.startDuty = async function(){ const type=document.getElementById('duty-type').value,loc=document.getElementById('duty-loc').value.trim()||'Belirtilmedi',id=Date.now().toString(); await fsSet('duties',id,{id,userId:CU._id,author:CU.name,unit:CU.unit,type,loc,time:new Date().toLocaleTimeString('tr-TR')}); await logAct('Görev başlatıldı: '+type);renderDuties(); };
window.endDuty = async function(id){ await fsDel('duties',id);await logAct('Görev sonlandırıldı.');renderDuties();renderHome(); };

async function renderDocs(){ docTab(curDocTab,null); await fillTargetSelect('doc-target'); const tg=document.getElementById('tmpl-grid');if(tg)tg.innerHTML=TMPL.map((t,i)=>'<button class="btn-sm outline" style="font-size:10px" onclick="applyTmpl('+i+')">'+t.name+'</button>').join(''); }
window.docTab = function(t,btn){ curDocTab=t; ['write','archive','pending'].forEach(x=>{const el=document.getElementById('doc-'+x);if(el)el.style.display=(x===t?'block':'none');}); document.querySelectorAll('#tab-docs .tab-sw-btn').forEach(b=>b.classList.remove('active'));if(btn)btn.classList.add('active'); if(t==='archive')renderDocArchive();if(t==='pending')renderDocPending(); };
window.applyTmpl = function(i){ const tmpl=TMPL[i],sel=document.getElementById('doc-target'),tName=sel&&sel.options[sel.selectedIndex]?sel.options[sel.selectedIndex].text:'[Personel]'; document.getElementById('doc-type').value=tmpl.type; document.getElementById('doc-content').value=tmpl.text.replace('{target}',tName).replace('{date}',new Date().toLocaleDateString('tr-TR')); };
window.createDoc = async function(){ const type=document.getElementById('doc-type').value,sel=document.getElementById('doc-target'),targetId=sel.value,targetName=sel.options[sel.selectedIndex]?sel.options[sel.selectedIndex].text:'',content=document.getElementById('doc-content').value.trim(),privacy=document.getElementById('doc-privacy').value,al=document.getElementById('doc-alert'); if(!content||!targetName){al.innerHTML='<div class="alert alert-err">Tüm alanları doldurun.</div>';return;} const id=Date.now().toString(); await fsSet('docs',id,{id,type,targetId,targetName,authorId:CU._id,author:CU.name,content,privacy,date:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); await logAct('Belge: '+type+' → '+targetName); al.innerHTML='<div class="alert alert-ok">✔ Kaydedildi.</div>';document.getElementById('doc-content').value='';setTimeout(()=>al.innerHTML='',2500); };
window.previewDoc = function(){ const type=document.getElementById('doc-type').value,sel=document.getElementById('doc-target'),tName=sel&&sel.options[sel.selectedIndex]?sel.options[sel.selectedIndex].text:'-',content=document.getElementById('doc-content').value; document.getElementById('doc-preview-box').style.display='block'; document.getElementById('doc-preview-content').innerHTML='<div style="border:1px solid var(--brown);border-radius:6px;padding:1.25rem;font-size:13px;line-height:1.8"><div style="display:flex;justify-content:space-between;margin-bottom:1rem;padding-bottom:.75rem;border-bottom:1px solid var(--brown)"><b style="font-family:\'Bebas Neue\',sans-serif;letter-spacing:2px">'+type+'</b><span style="font-size:11px;color:var(--muted)">'+new Date().toLocaleDateString('tr-TR')+'</span></div><div style="margin-bottom:.5rem"><b>Hedef:</b> '+tName+'</div><div style="margin-bottom:.5rem"><b>Yazan:</b> '+CU.name+' ('+CU.rank+')</div><hr style="border-color:var(--brown);margin:.75rem 0"><div>'+content.replace(/\n/g,'<br>')+'</div></div>'; };
async function renderDocArchive(){ const docs=await fsAll('docs'),uid=CU._id,isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin; const q=(document.getElementById('doc-search')||{}).value||''; let visible=isCmd?docs:docs.filter(d=>d.privacy!=='private'||d.authorId===uid||d.targetId===uid); if(q)visible=visible.filter(d=>(d.type+d.targetName+d.author).toLowerCase().includes(q.toLowerCase())); document.getElementById('doc-archive-list').innerHTML=visible.length?visible.slice().reverse().map(d=>docRow(d)).join(''):'<div class="empty">Belge yok.</div>'; }
async function renderDocPending(){ const docs=(await fsAll('docs')).filter(d=>d.status==='Bekliyor'); document.getElementById('doc-pending-list').innerHTML=docs.length?docs.map(d=>docRow(d,true)).join(''):'<div class="empty">Onay bekleyen yok.</div>'; }
window.approveDoc = async function(id){ const d=await fsGet('docs',id);if(d){d.status='Onaylandı';await fsSet('docs',id,d);}await logAct('Belge onaylandı.');renderDocPending(); };
function docRow(d,showApprove){ const isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin; return '<div class="pcard" style="margin-bottom:.5rem;display:flex;justify-content:space-between;align-items:center"><div><span class="badge b-gold">'+d.type+'</span> <span style="font-size:12px">→ '+d.targetName+'</span><br><span style="font-size:10px;color:var(--muted)">'+d.author+' · '+d.date+(d.privacy==='private'?' · 🔒':'')+'</span></div><div>'+(showApprove&&isCmd?'<button class="act-btn green" onclick="approveDoc(\''+d._id+'\')">Onayla</button>':'')+'<span class="badge '+(d.status==='Onaylandı'?'b-green':'b-warn')+'">'+d.status+'</span></div></div>'; }

async function renderLeave(){ const uid=CU._id,isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin,leaves=await fsAll('leaves'),mine=leaves.filter(l=>l.userId===uid); document.getElementById('leave-list').innerHTML=mine.length?mine.slice().reverse().map(l=>'<div class="pcard" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><div><b>'+l.type+'</b> <span style="color:var(--muted);font-size:12px">'+l.start+' – '+l.end+'</span></div><span class="badge '+(l.status==='Onaylandı'?'b-green':l.status==='Reddedildi'?'b-red':'b-warn')+'">'+l.status+'</span></div>').join(''):'<div class="empty">İzin kaydı yok.</div>'; const sec=document.getElementById('leave-approve-section');if(sec)sec.style.display=isCmd?'block':'none'; if(isCmd){ const pending=leaves.filter(l=>l.status==='Bekliyor'); document.getElementById('leave-pending-list').innerHTML=pending.length?pending.map(l=>'<div class="pcard" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><div><b>'+l.userName+'</b> — '+l.type+'<br><span style="font-size:11px;color:var(--muted)">'+l.start+' – '+l.end+'</span></div><div><button class="act-btn green" onclick="approveLeave(\''+l._id+'\',true)">Onayla</button><button class="act-btn red" onclick="approveLeave(\''+l._id+'\',false)">Reddet</button></div></div>').join(''):'<div class="empty">Bekleyen yok.</div>'; } }
window.sendLeave = async function(){ const start=document.getElementById('leave-start').value,end=document.getElementById('leave-end').value,type=document.getElementById('leave-type').value,desc=document.getElementById('leave-desc').value.trim(),al=document.getElementById('leave-alert'); if(!start||!end){al.innerHTML='<div class="alert alert-err">Tarih boş olamaz.</div>';return;} const id=Date.now().toString(); await fsSet('leaves',id,{id,userId:CU._id,userName:CU.name,type,start,end,desc,date:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); await logAct('İzin talebi: '+type); al.innerHTML='<div class="alert alert-ok">✔ Gönderildi.</div>';setTimeout(()=>al.innerHTML='',2500);renderLeave();buildSidebar(); };
window.approveLeave = async function(id,ok){ const l=await fsGet('leaves',id);if(!l)return;l.status=ok?'Onaylandı':'Reddedildi';await fsSet('leaves',id,l);await logAct('İzin '+(ok?'onaylandı':'reddedildi')+': '+l.userName);await addNotif(l.userName+' izin '+(ok?'onaylandı ✔':'reddedildi ✖'));renderLeave();buildSidebar(); };

async function renderDutyLog(){ const uid=CU._id,log=await fsAll('dutylog');const q=(document.getElementById('gl-search')||{}).value||'';let mine=log.filter(d=>d.userId===uid);if(q)mine=mine.filter(d=>(d.type+d.detail).toLowerCase().includes(q.toLowerCase())); document.getElementById('duty-log-list').innerHTML=mine.length?'<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Tür</th><th>Süre</th><th>Detay</th><th>Tarih</th></tr></thead><tbody>'+mine.slice().reverse().map(d=>'<tr><td><span class="badge b-gold">'+d.type+'</span></td><td>'+d.dur+'s</td><td style="color:var(--muted)">'+d.detail.slice(0,40)+'</td><td style="font-size:11px;color:var(--muted)">'+d.date+'</td></tr>').join('')+'</tbody></table></div>':'<div class="empty">Görev kaydı yok.</div>'; }
window.addDutyLog = async function(){ const type=document.getElementById('gl-type').value,dur=document.getElementById('gl-dur').value||1,detail=document.getElementById('gl-detail').value.trim();if(!detail){alert('Detay boş olamaz.');return;} const id=Date.now().toString(); await fsSet('dutylog',id,{id,userId:CU._id,type,dur,detail,date:new Date().toLocaleDateString('tr-TR')}); await logAct('Görev logu: '+type+' ('+dur+'s)'); document.getElementById('gl-detail').value='';renderDutyLog(); };

async function renderDisc(){ await fillTargetSelect('warn-target'); const uid=CU._id,warns=await fsAll('warns'),isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin; const visible=isCmd?warns:warns.filter(w=>w.targetId===uid||w.authorId===uid); document.getElementById('discipline-list').innerHTML=visible.length?'<div class="tbl-wrap"><table class="tbl"><thead><tr><th>Personel</th><th>Tür</th><th>Neden</th><th>Veren</th><th>Tarih</th></tr></thead><tbody>'+visible.slice().reverse().map(w=>'<tr><td>'+w.targetName+'</td><td><span class="badge b-red">'+w.type+'</span></td><td style="color:var(--muted);font-size:11px">'+w.desc.slice(0,30)+'</td><td>'+w.author+'</td><td style="font-size:11px;color:var(--muted)">'+w.date+'</td></tr>').join('')+'</tbody></table></div>':'<div class="empty">Disiplin kaydı yok.</div>'; }
window.addWarning = async function(){ const sel=document.getElementById('warn-target'),targetId=sel.value,targetName=sel.options[sel.selectedIndex]?sel.options[sel.selectedIndex].text:'',type=document.getElementById('warn-type').value,desc=document.getElementById('warn-desc').value.trim(),al=document.getElementById('disc-alert'); if(!desc||!targetName){al.innerHTML='<div class="alert alert-err">Tüm alanları doldurun.</div>';return;} const id=Date.now().toString(); await fsSet('warns',id,{id,targetId,targetName,authorId:CU._id,author:CU.name,type,desc,date:new Date().toLocaleDateString('tr-TR')}); const pers=await fsAll('pers');const p=pers.find(x=>x._id===targetId);if(p){p.warns=(p.warns||0)+1;await fsSet('pers',p._id,p);} await addNotif(targetName+' için "'+type+'" uyarısı.');await logAct('"'+type+'" → '+targetName); al.innerHTML='<div class="alert alert-ok">✔ Kaydedildi.</div>';document.getElementById('warn-desc').value='';setTimeout(()=>al.innerHTML='',2500);renderDisc(); };

async function renderPromo(){ await fillTargetSelect('promo-target'); const rankSel=document.getElementById('promo-rank');if(rankSel)rankSel.innerHTML=RANKS.map(r=>'<option>'+r+'</option>').join(''); const promos=await fsAll('promos'),isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin; document.getElementById('promo-list').innerHTML=promos.length?promos.slice().reverse().map(p=>{const badge=p.status==='Onaylandı'?'<span class="badge b-green">Onaylandı</span>':p.status==='Reddedildi'?'<span class="badge b-red">Reddedildi</span>':isCmd?'<button class="act-btn green" onclick="approvePromo(\''+p._id+'\',true)">Onayla</button><button class="act-btn red" onclick="approvePromo(\''+p._id+'\',false)">Reddet</button>':'<span class="badge b-warn">Bekliyor</span>';return '<div class="pcard" style="display:flex;align-items:center;justify-content:space-between;margin-bottom:.5rem"><div><b>'+p.targetName+'</b> → <span class="badge b-gold">'+p.newRank+'</span><br><span style="font-size:10px;color:var(--muted)">'+p.author+' · '+p.date+'</span></div><div>'+badge+'</div></div>';}).join(''):'<div class="empty">Terfi teklifi yok.</div>'; }
window.sendPromo = async function(){ const sel=document.getElementById('promo-target'),targetId=sel.value,targetName=sel.options[sel.selectedIndex]?sel.options[sel.selectedIndex].text:'',newRank=document.getElementById('promo-rank').value,reason=document.getElementById('promo-reason').value.trim(),al=document.getElementById('promo-alert'); if(!reason||!targetName){al.innerHTML='<div class="alert alert-err">Tüm alanları doldurun.</div>';return;} const id=Date.now().toString(); await fsSet('promos',id,{id,targetId,targetName,newRank,author:CU.name,reason,date:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); await addNotif(targetName+' için terfi → '+newRank);await logAct('Terfi teklifi: '+targetName+' → '+newRank); al.innerHTML='<div class="alert alert-ok">✔ Gönderildi.</div>';document.getElementById('promo-reason').value='';setTimeout(()=>al.innerHTML='',2500);renderPromo();buildSidebar(); };
window.approvePromo = async function(id,ok){ const p=await fsGet('promos',id);if(!p)return;p.status=ok?'Onaylandı':'Reddedildi'; if(ok){const pers=await fsAll('pers');const per=pers.find(x=>x._id===p.targetId);if(per){per.rank=p.newRank;await fsSet('pers',per._id,per);if(CU._id===per._id)CU.rank=p.newRank;}} await fsSet('promos',id,p);await addNotif(p.targetName+' terfi '+(ok?'onaylandı ✔':'reddedildi ✖'));await logAct('Terfi '+(ok?'onaylandı':'reddedildi')+': '+p.targetName);renderPromo();buildSidebar(); };

async function renderPersonnel(){ const rankSel=document.getElementById('p-nr');if(rankSel)rankSel.innerHTML=RANKS.map(r=>'<option>'+r+'</option>').join(''); const pers=await fsAll('pers');const q=(document.getElementById('pers-search')||{}).value||''; const p2=q?pers.filter(p=>(p.name+p.rank+p.unit).toLowerCase().includes(q.toLowerCase())):pers; p2.sort((a,b)=>RL[b.rank]-RL[a.rank]); document.getElementById('pers-tbody').innerHTML=p2.map(p=>'<tr><td>'+p.name+(p.isAdmin?' <span class="badge b-red" style="font-size:9px">A</span>':'')+'</td><td><span class="badge b-gold">'+p.rank+'</span></td><td style="font-size:11px;color:var(--muted)">'+p.unit+'</td><td><span class="badge b-muted">'+p.badge+'</span></td><td><span class="badge '+(p.warns?'b-red':'b-muted')+'">'+(p.warns||0)+'</span></td><td><button class="act-btn" onclick="editRank(\''+p._id+'\')">Rütbe</button><button class="act-btn red" onclick="delPers(\''+p._id+'\')">Sil</button></td></tr>').join(''); }
window.editRank = async function(id){ const pers=await fsAll('pers');const p=pers.find(x=>x._id===id);if(!p)return;const nr=prompt('Yeni rütbe:\n'+RANKS.join(', '),p.rank);if(!nr||!RANKS.includes(nr)){if(nr)alert('Geçersiz rütbe!');return;}p.rank=nr;await fsSet('pers',id,p);await logAct(p.name+' rütbesi → '+nr);renderPersonnel(); };
window.delPers  = async function(id){ if(!confirm('Bu personeli silmek istiyor musunuz?'))return; await fsDel('pers',id);await logAct('Personel silindi.');renderPersonnel(); };

async function fillTargetSelect(selId){ const sel=document.getElementById(selId);if(!sel)return; const pers=await fsAll('pers'),uid=CU._id,isCmd=RL[CU.rank]>=RL['Under Sheriff']||CU.isAdmin; const targets=isCmd?pers.filter(p=>p._id!==uid):pers.filter(p=>RL[p.rank]<RL[CU.rank]); sel.innerHTML=targets.map(p=>'<option value="'+p._id+'">'+p.name+'</option>').join(''); }

async function renderMyDMs(){ const el=document.getElementById('my-dms-list');if(!el)return; const uid=CU._id,dms=await fsAll('dm'),mine=dms.filter(m=>m.to===uid); if(!mine.length){el.innerHTML='<div class="empty">Gelen kutusu boş.</div>';return;} const convs={}; mine.forEach(m=>{if(!convs[m.from])convs[m.from]=[];convs[m.from].push(m);}); el.innerHTML=Object.keys(convs).map(from=>{const msgs=convs[from],last=msgs[msgs.length-1],unread=msgs.filter(m=>!m.read).length;return '<div class="pcard" style="margin-bottom:.5rem"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:.5rem"><span style="font-weight:600;color:var(--gold)">'+last.fromName+'</span>'+(unread?'<span class="badge b-red">'+unread+' yeni</span>':'<span class="badge b-muted">Okundu</span>')+'</div>'+msgs.slice(-3).map(m=>'<div style="background:var(--bg3);border-radius:4px;padding:6px 10px;margin-bottom:4px;font-size:12px"><span style="color:var(--muted);font-size:10px">'+m.time+'</span> '+m.text+'</div>').join('')+'</div>';}).join('');}

window.saveApply     = async function(data){ const id=Date.now().toString(); await fsSet('applies',id,{id,name:data.name||'',discord:data.discord||'',unit:data.unit||'',experience:data.experience||'',rpExp:data.rpExp||'',reason:data.reason||'',date:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); };
window.saveComplaint = async function(data){ const id=Date.now().toString(); await fsSet('complaints',id,{id,name:data.name||'',target:data.target||'',date:data.incidentDate||'',location:data.location||'',desc:data.desc||'',submitDate:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); };
window.savePraise    = async function(data){ const id=Date.now().toString(); await fsSet('praises',id,{id,name:data.name||'',target:data.target||'',date:new Date().toLocaleDateString('tr-TR'),desc:data.desc||''}); };
window.saveTicket    = async function(data){ const id=Date.now().toString(); await fsSet('tickets',id,{id,name:data.name||'',discord:data.discord||'',category:data.category||'',subject:data.subject||'',desc:data.desc||'',date:new Date().toLocaleDateString('tr-TR'),status:'Bekliyor'}); };

window.getPersForRoster = async function(){ return await fsAll('pers'); };
window.getHQPosts       = async function(){ return await fsAll('hq'); };
window.getGallery       = async function(){ return await fsAll('gallery'); };

initData();
